31	
32	/******************************************************************************/
33	/**
34	 * This function is called to wake-up the monitor from sleep.
35	 *
36	 * @param	RunCfgPtr is a pointer to the application configuration structure.
37	 *
38	 * @return	None.
39	 *
40	 * @note	None.
41	 *
42	*******************************************************************************/
43	static u32 DpPsu_Wakeup(Run_Config *RunCfgPtr)
44	{
45		u32 Status;
46		u8 AuxData;
47	
48		AuxData = 0x1;
49		Status = XDpPsu_AuxWrite(RunCfgPtr->DpPsuPtr,
50				XDPPSU_DPCD_SET_POWER_DP_PWR_VOLTAGE, 1, &AuxData);
51		if (Status != XST_SUCCESS)
52			xil_printf("\t! 1st power wake-up - AUX write failed.\n\r");
53		Status = XDpPsu_AuxWrite(RunCfgPtr->DpPsuPtr,
54				XDPPSU_DPCD_SET_POWER_DP_PWR_VOLTAGE, 1, &AuxData);
55		if (Status != XST_SUCCESS)
56			xil_printf("\t! 2nd power wake-up - AUX write failed.\n\r");
57	
58		return Status;
59	}
60	
61	/******************************************************************************/
62	/**
63	 * This function is called to initiate training with the source device, using
64	 * the predefined source configuration as well as the sink capabilities.
65	 *
66	 * @param	RunCfgPtr is a pointer to the application configuration structure.
67	 *
68	 * @return	XST_SUCCESS if the function executes correctly.
69	 * 			XST_FAILURE if the function fails to execute correctly
70	 *
71	 * @note	None.
72	*******************************************************************************/
73	static u32 DpPsu_Hpd_Train(Run_Config *RunCfgPtr)
74	{
75		XDpPsu		 *DpPsuPtr    = RunCfgPtr->DpPsuPtr;
76		XDpPsu_LinkConfig *LinkCfgPtr = &DpPsuPtr->LinkConfig;
77		u32 Status;
78	
79		Status = XDpPsu_GetRxCapabilities(DpPsuPtr);
80		if (Status != XST_SUCCESS) {
81			xil_printf("\t! Error getting RX caps.\n\r");
82			return XST_FAILURE;
83		}
84	
85		Status = XDpPsu_SetEnhancedFrameMode(DpPsuPtr,
86				LinkCfgPtr->SupportEnhancedFramingMode ? 1 : 0);
87		if (Status != XST_SUCCESS) {
88			xil_printf("\t! EFM set failed.\n\r");
89			return XST_FAILURE;
90		}
91	
92		Status = XDpPsu_SetLaneCount(DpPsuPtr,
93				(RunCfgPtr->UseMaxLaneCount) ?
94					LinkCfgPtr->MaxLaneCount :
95					RunCfgPtr->LaneCount);
96		if (Status != XST_SUCCESS) {
97			xil_printf("\t! Lane count set failed.\n\r");
98			return XST_FAILURE;
99		}
100	
101		Status = XDpPsu_SetLinkRate(DpPsuPtr,
102				(RunCfgPtr->UseMaxLinkRate) ?
103					LinkCfgPtr->MaxLinkRate :
104					RunCfgPtr->LinkRate);
105		if (Status != XST_SUCCESS) {
106			xil_printf("\t! Link rate set failed.\n\r");
107			return XST_FAILURE;
108		}
109	
110		Status = XDpPsu_SetDownspread(DpPsuPtr,
111				LinkCfgPtr->SupportDownspreadControl);
112		if (Status != XST_SUCCESS) {
113			xil_printf("\t! Setting downspread failed.\n\r");
114			return XST_FAILURE;
115		}
116	
117		xil_printf("Lane count =\t%d\n\r", DpPsuPtr->LinkConfig.LaneCount);
118		xil_printf("Link rate =\t%d\n\r",  DpPsuPtr->LinkConfig.LinkRate);
119	
120		// Link training sequence is done
121	        xil_printf("\n\r\rStarting Training...\n\r");
122		Status = XDpPsu_EstablishLink(DpPsuPtr);
123		if (Status == XST_SUCCESS)
124			xil_printf("\t! Training succeeded.\n\r");
125		else
126			xil_printf("\t! Training failed.\n\r");
127	
128		return Status;
129	}
130	
131	
132	/******************************************************************************/
133	/**
134	 * This function will configure and establish a link with the receiver device,
135	 * afterwards, a video stream will start to be sent over the main link.
136	 *
137	 * @param	RunCfgPtr is a pointer to the application configuration structure.
138	 *
139	 * @return
140	 *		- XST_SUCCESS if main link was successfully established.
141	 *		- XST_FAILURE otherwise.
142	 *
143	 * @note	None.
144	 *
145	*******************************************************************************/
146	void DpPsu_Run(Run_Config *RunCfgPtr)
147	{
148		u32 Status;
149		XDpPsu  *DpPsuPtr = RunCfgPtr->DpPsuPtr;
150	
151		Status = InitDpDmaSubsystem(RunCfgPtr);
152		if (Status != XST_SUCCESS) {
153			xil_printf("! InitDpDmaSubsystem failed.\n\r");
154			return;
155		}
156	
157		XDpPsu_EnableMainLink(DpPsuPtr, 0);
158	
159		if (!XDpPsu_IsConnected(DpPsuPtr)) {
160			XDpDma_SetChannelState(RunCfgPtr->DpDmaPtr, GraphicsChan,
161					       XDPDMA_DISABLE);
162			xil_printf("! Disconnected.\n\r");
163			return;
164		}
165		else {
166			xil_printf("! Connected.\n\r");
167		}
168	
169		Status = DpPsu_Wakeup(RunCfgPtr);
170		if (Status != XST_SUCCESS) {
171			xil_printf("! Wakeup failed.\n\r");
172			return;
173		}
174	
175	
176		u8 Count = 0;
177		do {
178			usleep(100000);
179			Count++;
180	
181			Status = DpPsu_Hpd_Train(RunCfgPtr);
182			if (Status == XST_DEVICE_NOT_FOUND) {
183				xil_printf("Lost connection\n\r");
184				return;
185			}
186			else if (Status != XST_SUCCESS)
187				continue;
188	
189	#ifdef GRAPHIC_BUFFER_EN
190			XDpDma_DisplayGfxFrameBuffer(RunCfgPtr->DpDmaPtr, &GFrameBuffer);
191	#endif
192	
193	#ifdef VIDEO_BUFFER_EN
194			XDpDma_DisplayVideoFrameBuffer(RunCfgPtr->DpDmaPtr,&VFrameBuffer,NULL,NULL);
195	#endif
196			DpPsu_SetupVideoStream(RunCfgPtr);
197			XDpPsu_EnableMainLink(DpPsuPtr, 1);
198	
199			Status = XDpPsu_CheckLinkStatus(DpPsuPtr, DpPsuPtr->LinkConfig.LaneCount);
200			if (Status == XST_DEVICE_NOT_FOUND)
201				return;
202		} while ((Status != XST_SUCCESS) && (Count < 2));
203	}
204	
205	/******************************************************************************/
206	/**
207	 * This function is called when a Hot-Plug-Detect (HPD) event is received by the
208	 * DisplayPort TX core. The XDPPSU_INTERRUPT_STATUS_HPD_EVENT_MASK bit of the
209	 * core's XDPPSU_INTERRUPT_STATUS register indicates that an HPD event has
210	 * occurred.
211	 *
212	 * @param	InstancePtr is a pointer to the XDpPsu instance.
213	 *
214	 * @return	None.
215	 *
216	 * @note	Use the XDpPsu_SetHpdEventHandler driver function to set this
217	 *		function as the handler for HPD pulses.
218	 *
219	*******************************************************************************/
220	void DpPsu_IsrHpdEvent(void *ref)
221	{
222		xil_printf("HPD event .......... ");
223		DpPsu_Run((Run_Config *)ref);
224		xil_printf(".......... HPD event\n\r");
225	}
226	/******************************************************************************/
227	/**
228	 * This function is called when a Hot-Plug-Detect (HPD) pulse is received by the
229	 * DisplayPort TX core. The XDPPSU_INTERRUPT_STATUS_HPD_PULSE_DETECTED_MASK bit
230	 * of the core's XDPPSU_INTERRUPT_STATUS register indicates that an HPD event has
231	 * occurred.
232	 *
233	 * @param	InstancePtr is a pointer to the XDpPsu instance.
234	 *
235	 * @return	None.
236	 *
237	 * @note	Use the XDpPsu_SetHpdPulseHandler driver function to set this
238	 *		function as the handler for HPD pulses.
239	 *
240	*******************************************************************************/
241	void DpPsu_IsrHpdPulse(void *ref)
242	{
243		u32 Status;
244		XDpPsu *DpPsuPtr = ((Run_Config *)ref)->DpPsuPtr;
245		xil_printf("HPD pulse ..........\n\r");
246	
247		Status = XDpPsu_CheckLinkStatus(DpPsuPtr, DpPsuPtr->LinkConfig.LaneCount);
248		if (Status == XST_DEVICE_NOT_FOUND) {
249			xil_printf("Lost connection .......... HPD pulse\n\r");
250			return;
251		}
252	
253		xil_printf("\t! Re-training required.\n\r");
254	
255		XDpPsu_EnableMainLink(DpPsuPtr, 0);
256	
257		u8 Count = 0;
258		do {
259			Count++;
260	
261			Status = DpPsu_Hpd_Train((Run_Config *)ref);
262			if (Status == XST_DEVICE_NOT_FOUND) {
263				xil_printf("Lost connection .......... HPD pulse\n\r");
264				return;
265			}
266			else if (Status != XST_SUCCESS) {
267				continue;
268			}
269	
270			DpPsu_SetupVideoStream((Run_Config *)ref);
271			XDpPsu_EnableMainLink(DpPsuPtr, 1);
272	
273			Status = XDpPsu_CheckLinkStatus(DpPsuPtr, DpPsuPtr->LinkConfig.LaneCount);
274			if (Status == XST_DEVICE_NOT_FOUND) {
275				xil_printf("Lost connection .......... HPD pulse\n\r");
276				return;
277			}
278		} while ((Status != XST_SUCCESS) && (Count < 2));
279	
280		xil_printf(".......... HPD pulse\n\r");
281	}
282	
283	
284	void DpPsu_SetupVideoStream(Run_Config *RunCfgPtr)
285	{
286		XDpPsu		 *DpPsuPtr    = RunCfgPtr->DpPsuPtr;
287		XDpPsu_MainStreamAttributes *MsaConfig = &DpPsuPtr->MsaConfig;
288	
289		XDpPsu_SetColorEncode(DpPsuPtr, RunCfgPtr->ColorEncode);
290		XDpPsu_CfgMsaSetBpc(DpPsuPtr, RunCfgPtr->Bpc);
291		XDpPsu_CfgMsaUseStandardVideoMode(DpPsuPtr, RunCfgPtr->VideoMode);
292	
293		/* Set pixel clock. */
294		RunCfgPtr->PixClkHz = MsaConfig->PixelClockHz;
295		XAVBuf_SetPixelClock(RunCfgPtr->PixClkHz);
296	
297		/* Reset the transmitter. */
298		XDpPsu_WriteReg(DpPsuPtr->Config.BaseAddr, XDPPSU_SOFT_RESET, 0x1);
299		usleep(10);
300		XDpPsu_WriteReg(DpPsuPtr->Config.BaseAddr, XDPPSU_SOFT_RESET, 0x0);
301	
302		XDpPsu_SetMsaValues(DpPsuPtr);
303		/* Issuing a soft-reset (AV_BUF_SRST_REG). */
304		XDpPsu_WriteReg(DpPsuPtr->Config.BaseAddr, 0xB124, 0x3); // Assert reset.
305		usleep(10);
306		XDpPsu_WriteReg(DpPsuPtr->Config.BaseAddr, 0xB124, 0x0); // De-ssert reset.
307		usleep(10);
308		XDpPsu_EnableMainLink(DpPsuPtr, 1);
309	
310		xil_printf("DONE!\n\r");
311	}
312	
313	
314	void Dpdma_Setup_Intr_System(Run_Config *RunCfgPtr)
315	{
316		XDpPsu 	 *DpPsuPtr = RunCfgPtr->DpPsuPtr;
317		XScuGic	 *IntrPtr  = RunCfgPtr->IntrPtr;
318	
319		u32  IntrMask = XDPPSU_INTR_HPD_IRQ_MASK | XDPPSU_INTR_HPD_EVENT_MASK;
320	
321		XDpPsu_WriteReg(DpPsuPtr->Config.BaseAddr, XDPPSU_INTR_DIS, 0xFFFFFFFF);
322		XDpPsu_WriteReg(DpPsuPtr->Config.BaseAddr, XDPPSU_INTR_MASK, 0xFFFFFFFF);
323	
324		XDpPsu_SetHpdEventHandler(DpPsuPtr, DpPsu_IsrHpdEvent, RunCfgPtr);
325		XDpPsu_SetHpdPulseHandler(DpPsuPtr, DpPsu_IsrHpdPulse, RunCfgPtr);
326	
327		/* Register ISRs. */
328		XScuGic_Connect(IntrPtr, DPPSU_INTR_ID,(Xil_InterruptHandler)XDpPsu_HpdInterruptHandler, RunCfgPtr->DpPsuPtr);
329	
330		/* Trigger DP interrupts on rising edge. */
331		XScuGic_SetPriorityTriggerType(IntrPtr, DPPSU_INTR_ID, 0x0, 0x03);
332	
333		/* Connect DPDMA Interrupt */
334		XScuGic_Connect(IntrPtr, DPDMA_INTR_ID,(Xil_ExceptionHandler)XDpDma_InterruptHandler, RunCfgPtr->DpDmaPtr);
335	
336		/* Enable DP interrupts. */
337		XScuGic_Enable(IntrPtr, DPPSU_INTR_ID);
338		XDpPsu_WriteReg(DpPsuPtr->Config.BaseAddr, XDPPSU_INTR_EN, IntrMask);
339	
340		/* Enable DPDMA Interrupts */
341		XScuGic_Enable(IntrPtr, DPDMA_INTR_ID);
342		XDpDma_InterruptEnable(RunCfgPtr->DpDmaPtr, XDPDMA_IEN_VSYNC_INT_MASK);
343	}
344	
345	
346	int InitDpDmaSubsystem(Run_Config *RunCfgPtr )
347	{
348		u32 Status;
349		XDpPsu		*DpPsuPtr = RunCfgPtr->DpPsuPtr;
350		XDpPsu_Config	*DpPsuCfgPtr;
351		XAVBuf		*AVBufPtr = RunCfgPtr->AVBufPtr;
352		XDpDma_Config *DpDmaCfgPtr;
353		XDpDma		*DpDmaPtr = RunCfgPtr->DpDmaPtr;
354	
355	
356		/* Initialize DisplayPort driver. */
357		DpPsuCfgPtr = XDpPsu_LookupConfig(DPPSU_DEVICE_ID);
358		XDpPsu_CfgInitialize(DpPsuPtr, DpPsuCfgPtr, DpPsuCfgPtr->BaseAddr);
359		/* Initialize Video Pipeline driver */
360		XAVBuf_CfgInitialize(AVBufPtr, DpPsuPtr->Config.BaseAddr, AVBUF_DEVICE_ID);
361	
362		/* Initialize the DPDMA driver */
363		DpDmaCfgPtr = XDpDma_LookupConfig(DPDMA_DEVICE_ID);
364		XDpDma_CfgInitialize(DpDmaPtr,DpDmaCfgPtr);
365	
366		/* Initialize the DisplayPort TX core. */
367		Status = XDpPsu_InitializeTx(DpPsuPtr);
368		if (Status != XST_SUCCESS) {
369			return XST_FAILURE;
370		}
371	
372		/* Set the format graphics frame for DPDMA*/
373		Status = XDpDma_SetVideoFormat(DpDmaPtr, RGBA8880);
374		if (Status != XST_SUCCESS) {
375				return XST_FAILURE;
376		}
377	
378		/* Set the format graphics frame for DPDMA*/
379		Status = XDpDma_SetGraphicsFormat(DpDmaPtr, RGBA8888);
380		if (Status != XST_SUCCESS) {
381				return XST_FAILURE;
382		}
383	
384		Status = XAVBuf_SetInputNonLiveVideoFormat(AVBufPtr, RGBA8880);
385		if (Status != XST_SUCCESS) {
386				return XST_FAILURE;
387		}
388		/* Set the format graphics frame for Video Pipeline*/
389		Status = XAVBuf_SetInputNonLiveGraphicsFormat(AVBufPtr, RGBA8888);
390		if (Status != XST_SUCCESS) {
391				return XST_FAILURE;
392		}
393	
394		/* Set the QOS for Video */
395		XDpDma_SetQOS(RunCfgPtr->DpDmaPtr, 11);
396		/* Enable the Buffers required by Graphics Channel */
397		XAVBuf_EnableVideoBuffers(RunCfgPtr->AVBufPtr, 1);
398		XAVBuf_EnableGraphicsBuffers(RunCfgPtr->AVBufPtr, 1);
399		/* Set the output Video Format */
400		XAVBuf_SetOutputVideoFormat(AVBufPtr, RGB_8BPC);
401	
402		/* Select the Input Video Sources.
403		 * Here in this example we are going to demonstrate
404		 * graphics overlay over the TPG video.
405		 */
406		XAVBuf_InputVideoSelect(AVBufPtr, XAVBUF_VIDSTREAM1_NONLIVE,XAVBUF_VIDSTREAM2_NONLIVE_GFX);
407		/* Configure Video pipeline for graphics channel */
408		XAVBuf_ConfigureVideoPipeline(AVBufPtr);
409		XAVBuf_ConfigureGraphicsPipeline(AVBufPtr);
410		/* Configure the output video pipeline */
411		XAVBuf_ConfigureOutputVideo(AVBufPtr);
412		/* Disable the global alpha, since we are using the pixel based alpha */
413		XAVBuf_SetBlenderAlpha(AVBufPtr, 0, 0);
414		/* Set the clock mode */
415		XDpPsu_CfgMsaEnSynchClkMode(DpPsuPtr, RunCfgPtr->EnSynchClkMode);
416		/* Set the clock source depending on the use case.
417		 * Here for simplicity we are using PS clock as the source*/
418		XAVBuf_SetAudioVideoClkSrc(AVBufPtr, XAVBUF_PS_CLK, XAVBUF_PS_CLK);
419		/* Issue a soft reset after selecting the input clock sources */
420		XAVBuf_SoftReset(AVBufPtr);
421	
422		return XST_SUCCESS;
423	}
424	
425	void graphic_buffer_update(u8* Frame, Run_Config *RunCfgPtr)
426	{
427		GFrameBuffer.Address = (INTPTR)Frame;
428		GFrameBuffer.Stride = STRIDE;
429		GFrameBuffer.LineSize = LINESIZE;
430		GFrameBuffer.Size = BUFFERSIZE;
431		XDpDma_DisplayGfxFrameBuffer(RunCfgPtr->DpDmaPtr, &GFrameBuffer);
432		return ;
433	}
434	
435	
436	void graphic_buffer_init(u8* Frame)
437	{
438		u32 vcnt,hcnt;
439		u32 *RGBA;
440		RGBA = (u32 *) Frame;
441	
442		for(vcnt =0 ; vcnt < 720 ; vcnt++)
443		{
444	
445			for(hcnt = 0; hcnt < 1280; hcnt++)
446				{
447	
448					if((hcnt&0x10)^(vcnt&0x10))
449						RGBA[hcnt+vcnt*1280] = 0x00000000;//Alpha = 0x00
450					else
451						RGBA[hcnt+vcnt*1280] = 0xffffffff;//Alpha = 0xff
452				}
453	
454		}
455		/* Populate the FrameBuffer structure with the frame attributes */
456		GFrameBuffer.Address = (INTPTR)Frame;
457		GFrameBuffer.Stride = STRIDE;
458		GFrameBuffer.LineSize = LINESIZE;
459		GFrameBuffer.Size = BUFFERSIZE;
460		return ;
461	}
462	
463	
464	void video_buffer_update(u8* Frame, Run_Config *RunCfgPtr)
465	{
466		VFrameBuffer.Address = (INTPTR)Frame;
467		VFrameBuffer.Stride = STRIDE;
468		VFrameBuffer.LineSize = LINESIZE;
469		VFrameBuffer.Size = BUFFERSIZE;
470		XDpDma_DisplayVideoFrameBuffer(RunCfgPtr->DpDmaPtr,&VFrameBuffer,NULL,NULL);
471		return ;
472	}
473	
474	void video_buffer_init(u8* Frame)
475	{
476		u32 vcnt,hcnt;
477		u32 *RGBA;
478		RGBA = (u32 *) Frame;
479	
480	
481		for(vcnt =0 ; vcnt < 720 ; vcnt++)
482		{
483	
484			for(hcnt = 0; hcnt < 1280; hcnt++)
485				{
486					RGBA[hcnt+vcnt*1280] = 0x000000FF;
487				}
488	
489		}
490		/* Populate the FrameBuffer structure with the frame attributes */
491		VFrameBuffer.Address = (INTPTR)Frame;
492		VFrameBuffer.Stride = STRIDE;
493		VFrameBuffer.LineSize = LINESIZE;
494		VFrameBuffer.Size = BUFFERSIZE;
495		return ;
496	}
497	
498	void InitRunConfig(Run_Config *RunCfgPtr ,XScuGic * IntcPtr)
499	{
500		/* Initial configuration parameters. */
501		RunCfgPtr->DpPsuPtr   			= &DpPsu;
502		RunCfgPtr->IntrPtr   			= IntcPtr;
503		RunCfgPtr->AVBufPtr  			= &AVBuf;
504		RunCfgPtr->DpDmaPtr  			= &DpDma;
505		RunCfgPtr->VideoMode 			= XVIDC_VM_1280x720_60_P;
506		RunCfgPtr->Bpc		 			= XVIDC_BPC_8;
507		RunCfgPtr->ColorEncode			= XDPPSU_CENC_RGB;
508		RunCfgPtr->UseMaxCfgCaps		= 1;
509		RunCfgPtr->LaneCount			= LANE_COUNT_2;
510		RunCfgPtr->LinkRate				= LINK_RATE_540GBPS;
511		RunCfgPtr->EnSynchClkMode		= 0;
512		RunCfgPtr->UseMaxLaneCount		= 1;
513		RunCfgPtr->UseMaxLinkRate		= 1;
514	
515	}
516	
517	int Dpdma_init(Run_Config *RunCfgPtr ,XScuGic * IntcPtr)
518	{
519		u32 Status;
520		/* Initialize the application configuration */
521		InitRunConfig(RunCfgPtr , IntcPtr);
522		Status = InitDpDmaSubsystem(RunCfgPtr);
523		if (Status != XST_SUCCESS) {
524					return XST_FAILURE;
525		}
526		return XST_SUCCESS;
527	}
