551		                #ifdef EEP_DP_ENABLE
552		                //dp display
553		                dp_display(pic_hsize, pic_vsize, img_data_888, ARGB);
554		                #endif
555					#endif
556	
557						Xil_DCacheFlush();
558						xil_printf("Image Capture Done\r\n");
559	
